/**
 * Deterministic calendar of scheduled events relevant to Bitcoin investors.
 *
 * Why this file exists: previously countdown_events were generated by Claude
 * from training data (cutoff Jan 2026), which produced hallucinated or stale
 * dates (wrong FOMC days, options expiry on a Saturday, etc.). Shipping wrong
 * dates on a paid briefing is a trust-killer.
 *
 * This file is the single source of truth. The AI brain prompt is given this
 * list verbatim and told to pick ONLY from it. After Claude returns, a
 * validator drops any event whose (name, date) pair is not in this file.
 *
 * ─────────────────────────────────────────────────────────────────────────
 *  MAINTENANCE: this file ships dates manually curated from official sources.
 *  Verify these at least once per year:
 *    - FOMC schedule:    https://www.federalreserve.gov/monetarypolicy/fomccalendars.htm
 *    - CPI releases:     https://www.bls.gov/schedule/news_release/cpi.htm
 *    - Jobs reports:     https://www.bls.gov/schedule/news_release/empsit.htm
 *    - PCE releases:     https://www.bea.gov/news/schedule
 *  Options expiry is computed mechanically (Deribit: last Friday of month,
 *  08:00 UTC). Halving is block-based (~block 1,050,000) and is emitted
 *  with a ±14 day caveat in its description.
 * ─────────────────────────────────────────────────────────────────────────
 */

export type KnownEventKind =
  | "fomc"
  | "cpi"
  | "jobs"
  | "pce"
  | "halving"
  | "options_expiry";

export interface KnownEvent {
  kind: KnownEventKind;
  name: string;        // Canonical display name shown on the site
  date: string;        // ISO date "YYYY-MM-DD"
  description: string; // One-line description for the UI card
}

